export type PrismGeneratedRuntimeOptions = RuntimeClientOptions & Partial<RuntimeDefaults>;

type ObjectRuntimeHandle<Record> = {
  readonly appId: string;
  readonly objectKind: string;
  readonly objectId: string;
  readonly shardId?: string;
  runtimeOptions(): ReadObjectOptions;
  read(options?: ReadObjectOptions): Promise<ObjectReadResponse<Record>>;
  property(property: keyof Record & string): {
    eq(value: unknown, options?: WatchPredicateOptions): Promise<WatchObjectPropertyResponse<Record>>;
  };
};

type SurfaceWatchHandle<Input, Record> = {
  readonly appId: string;
  readonly surfaceId: string;
  readonly kind: string;
  readonly watchable: true;
  query(input: Input, options?: QueryOptions): Promise<QueryResponse<Record>>;
};

function routeShardId<Record>(
  route: ObjectRoute<Record> | undefined,
  routeFor?: ObjectRouteResolver<Record>,
): string | undefined {
  if (!route) return undefined;
  if (typeof route === "string") return route;
  const explicit = (route as { shardId?: unknown }).shardId;
  if (typeof explicit === "string") return explicit;
  return routeFor?.(route as Partial<Record>);
}

function mergeShardOption<Options extends { shardId?: string }>(
  baseShardId: string | undefined,
  options: Options = {} as Options,
): Options {
  return baseShardId && !options.shardId ? { ...options, shardId: baseShardId } : options;
}

function objectHandle<Record>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  appId: string,
  objectKind: string,
  objectId: string,
  shardId?: string,
): ObjectRuntimeHandle<Record> {
  return {
    appId,
    objectKind,
    objectId,
    shardId,
    runtimeOptions: () => shardId ? { shardId } : {},
    read: (options = {}) => client.readObject<Record>(appId, objectKind, objectId, defaults, mergeShardOption(shardId, options)),
    property: (property) => ({
      eq: (value, options = {}) =>
        client.watchObjectProperty<Record>(appId, objectKind, objectId, property, value, defaults, mergeShardOption(shardId, options)),
    }),
  };
}

function surfaceWatchHandle<Input, Record>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  appId: string,
  surfaceId: string,
  kind: string,
): SurfaceWatchHandle<Input, Record> {
  return {
    appId,
    surfaceId,
    kind,
    watchable: true,
    query: (input, options = {}) => client.query<Input, Record>(appId, surfaceId, input, defaults, options),
  };
}

type ObjectKindRuntimeHandle<Record> = {
  byId(id: string, route?: ObjectRoute<Record>): ObjectRuntimeHandle<Record>;
  byRecord(record: Record & { id: string }): ObjectRuntimeHandle<Record>;
  shardIdFor(route: Partial<Record>): string | undefined;
  shardsFor(route: Partial<Record>): string[];
  waitFor(ids: string[], property: keyof Record & string, equals: unknown, options?: WatchPredicatesOptions): Promise<WatchObjectPropertiesResponse<Record>>;
};

function objectKindHandle<Record>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  appId: string,
  objectKind: string,
  routeFor?: ObjectRouteResolver<Record>,
  shardsFor?: (route: Partial<Record>) => string[],
): ObjectKindRuntimeHandle<Record> {
  return {
    byId: (id, route) => objectHandle<Record>(client, defaults, appId, objectKind, id, routeShardId(route, routeFor)),
    byRecord: (record) => objectHandle<Record>(client, defaults, appId, objectKind, String(record.id), routeShardId(record, routeFor)),
    shardIdFor: (route) => routeShardId(route, routeFor),
    shardsFor: (route) => shardsFor?.(route) ?? [routeShardId(route, routeFor) ?? defaults.shardId ?? ""].filter(Boolean),
    waitFor: (ids, property, equals, options = {}) =>
      client.watchObjectProperties<Record>(
        ids.map((id) => ({ appId, objectKind, objectId: id, property, equals })),
        defaults,
        options,
      ),
  };
}

type ReadPlanItem<Value> = {
  readonly kind: "read_object" | "query";
  batchItem(requestId: string): RuntimeBatchItem;
  decode(response: RuntimeBatchResponse): Value;
};

type ReadPlanResult<Plan extends Record<string, ReadPlanItem<unknown>>> = {
  [Key in keyof Plan]: Plan[Key] extends ReadPlanItem<infer Value> ? Value : never;
};

type ReadObjectPlanHandle<Record> = {
  read(options?: ReadObjectOptions): ReadPlanItem<ObjectReadResponse<Record>>;
};

type ReadObjectPlanKind<Record> = {
  byId(id: string, route?: ObjectRoute<Record>): ReadObjectPlanHandle<Record>;
  byRecord(record: Record & { id: string }): ReadObjectPlanHandle<Record>;
};

function readObjectPlanKind<Record>(
  appId: string,
  objectKind: string,
  routeFor?: ObjectRouteResolver<Record>,
): ReadObjectPlanKind<Record> {
  const makeHandle = (id: string, shardId?: string): ReadObjectPlanHandle<Record> => ({
    read: (options = {}) => ({
      kind: "read_object",
      batchItem: (requestId) => ({
        kind: "read_object",
        requestId,
        appId,
        objectKind,
        objectId: id,
        options: mergeShardOption(shardId, options),
      }),
      decode: (response) => {
        if (response.kind === "error") throw new Error(`${response.requestId}: ${response.message}`);
        if (response.kind !== "read_object") throw new Error(`expected read_object response for ${response.requestId}`);
        return response.response as ObjectReadResponse<Record>;
      },
    }),
  });
  return {
    byId: (id, route) => makeHandle(id, routeShardId(route, routeFor)),
    byRecord: (record) => makeHandle(String(record.id), routeShardId(record, routeFor)),
  };
}

function queryPlan<Input, Record>(
  appId: string,
  surfaceId: string,
  input: Input,
  options: QueryOptions = {},
): ReadPlanItem<QueryResponse<Record>> {
  return {
    kind: "query",
    batchItem: (requestId) => ({
      kind: "query",
      requestId,
      appId,
      surfaceId,
      input,
      options,
    }),
    decode: (response) => {
      if (response.kind === "error") throw new Error(`${response.requestId}: ${response.message}`);
      if (response.kind !== "query") throw new Error(`expected query response for ${response.requestId}`);
      return response.response as QueryResponse<Record>;
    },
  };
}

async function executeReadPlan<Plan extends Record<string, ReadPlanItem<unknown>>>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  plan: Plan,
): Promise<ReadPlanResult<Plan>> {
  const entries = Object.entries(plan) as [keyof Plan & string, ReadPlanItem<unknown>][];
  const responses = await client.batch(
    entries.map(([key, item]) => item.batchItem(key)),
    defaults,
  );
  const out: Record<string, unknown> = {};
  entries.forEach(([key, item], index) => {
    const response = responses[index];
    if (!response) throw new Error(`missing runtime response for ${key}`);
    out[key] = item.decode(response);
  });
  return out as ReadPlanResult<Plan>;
}

type WatchPlanPredicate<Record = any> = {
  appId: string;
  objectKind: string;
  objectId: string;
  property: keyof Record & string;
  equals: unknown;
  shardId?: string;
};

type WaitPlanOptions = WatchPredicatesOptions;

type WaitObjectPlanHandle<Record> = {
  exists(): WatchPlanPredicate<Record>;
  property(property: keyof Record & string): {
    eq(value: unknown): WatchPlanPredicate<Record>;
  };
};

type WaitObjectPlanKind<Record> = {
  byId(id: string, route?: ObjectRoute<Record>): WaitObjectPlanHandle<Record>;
  byRecord(record: Record & { id: string }): WaitObjectPlanHandle<Record>;
};

function waitObjectPlanKind<Record>(
  appId: string,
  objectKind: string,
  routeFor?: ObjectRouteResolver<Record>,
): WaitObjectPlanKind<Record> {
  const makeHandle = (id: string, shardId?: string): WaitObjectPlanHandle<Record> => ({
    exists: () => ({ appId, objectKind, objectId: id, property: "id" as keyof Record & string, equals: id, shardId }),
    property: (property) => ({
      eq: (equals) => ({ appId, objectKind, objectId: id, property, equals, shardId }),
    }),
  });
  return {
    byId: (id, route) => makeHandle(id, routeShardId(route, routeFor)),
    byRecord: (record) => makeHandle(String(record.id), routeShardId(record, routeFor)),
  };
}

async function executeWaitPlan(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  predicates: WatchPlanPredicate<any> | WatchPlanPredicate<any>[],
  options: WaitPlanOptions = {},
): Promise<WatchObjectPropertiesResponse<unknown>> {
  const items = Array.isArray(predicates) ? predicates : [predicates];
  if (items.length === 0) {
    throw new Error("wait plan must contain at least one watch predicate");
  }
  const byShard = new Map<string, WatchPlanPredicate[]>();
  for (const item of items) {
    const shardId = item.shardId ?? options.shardId ?? defaults.shardId ?? "";
    const group = byShard.get(shardId);
    if (group) group.push(item);
    else byShard.set(shardId, [item]);
  }
  const responses = await Promise.all(Array.from(byShard, ([shardId, shardPredicates]) =>
    client.watchObjectProperties(
      shardPredicates.map((predicate) => ({
        appId: predicate.appId,
        objectKind: predicate.objectKind,
        objectId: predicate.objectId,
        property: predicate.property,
        equals: predicate.equals,
      })),
      defaults,
      { ...options, shardId, matchMode: options.matchMode ?? "all" },
    )
  ));
  const matched = (options.matchMode ?? "all") === "any"
    ? responses.some((response) => response.matched)
    : responses.every((response) => response.matched);
  return {
    status: matched ? "matched" : responses[0]?.status ?? "closed",
    matched,
    results: responses.flatMap((response) => response.results),
    elapsed_ms: Math.max(...responses.map((response) => Number(response.elapsed_ms ?? 0))),
    attempts: Math.max(...responses.map((response) => response.attempts)),
    outbox_waits: responses.reduce((sum, response) => sum + response.outbox_waits, 0),
  };
}

type QueryRuntimeHandle<Input, Record> = {
  readonly appId: string;
  readonly surfaceId: string;
  run(input: Input, options?: QueryOptions): Promise<QueryResponse<Record>>;
  runOnShards(input: Input, shardIds: string[], options?: Omit<QueryOptions, "shardId" | "shardIds">): Promise<QueryResponse<Record>>;
};

function queryHandle<Input, Record>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  appId: string,
  surfaceId: string,
): QueryRuntimeHandle<Input, Record> {
  return {
    appId,
    surfaceId,
    run: (input, options = {}) => client.query<Input, Record>(appId, surfaceId, input, defaults, options),
    runOnShards: (input, shardIds, options = {}) =>
      client.query<Input, Record>(appId, surfaceId, input, defaults, { ...options, shardIds }),
  };
}

export type WorkflowRuntimeHandle<Input, Output, Metadata = Record<string, JsonValue>> = {
  readonly appId: string;
  readonly workflowId: string;
  readonly workflowKey: string;
  readonly workflowRef: string;
  readonly shardId?: string;
  start(): Promise<WorkflowStartResponse<Output, Input, Metadata>>;
  done(): Promise<Output>;
  read(): Promise<WorkflowReadResponse<Output, Input, Metadata>>;
  wait(options?: WorkflowWaitOptions): Promise<WorkflowReadResponse<Output, Input, Metadata>>;
  cancel(reason?: string, options?: WorkflowCancelOptions): Promise<WorkflowCancelResponse<Output, Input, Metadata>>;
  updateMetadata(metadata: Metadata, options?: WorkflowMetadataUpdateOptions): Promise<WorkflowMetadataUpdateResponse<Metadata>>;
  restart(input?: Input, options?: WorkflowStartOptions): Promise<WorkflowStartResponse<Output, Input, Metadata>>;
  explain(options?: WorkflowInspectOptions): Promise<WorkflowInspectResponse>;
};

export type WorkflowBenchmarkOptions = WorkflowWaitOptions & {
  concurrency?: number;
  includeExplain?: boolean;
};

export type WorkflowBenchmarkResult = {
  workflow_count: number;
  started: number;
  succeeded: number;
  failed: number;
  canceled: number;
  timed_out: number;
  terminal: number;
  elapsed_ms: number;
  statuses: Record<string, number>;
  same_turn_counters: Record<string, number>;
};

export async function benchmarkWorkflowHandles(
  handles: readonly WorkflowRuntimeHandle<any, any, any>[],
  options: WorkflowBenchmarkOptions = {},
): Promise<WorkflowBenchmarkResult> {
  const startedAt = Date.now();
  const statuses: Record<string, number> = {};
  const sameTurnCounters: Record<string, number> = {};
  let started = 0;
  let succeeded = 0;
  let failed = 0;
  let canceled = 0;
  let timedOut = 0;
  const concurrency = Math.max(1, options.concurrency ?? handles.length ?? 1);
  let nextIndex = 0;
  async function worker() {
    while (nextIndex < handles.length) {
      const handle = handles[nextIndex++];
      await handle.start();
      started += 1;
      const read = await handle.wait(options);
      const status = read.instance?.status ?? "missing";
      statuses[status] = (statuses[status] ?? 0) + 1;
      if (status === "succeeded") succeeded += 1;
      else if (status === "failed") failed += 1;
      else if (status === "canceled") canceled += 1;
      else if (status === "timed_out") timedOut += 1;
      if (options.includeExplain) {
        collectSameTurnCounters(await handle.explain({ includeIssueDetails: true }), sameTurnCounters);
      }
    }
  }
  await Promise.all(Array.from({ length: Math.min(concurrency, handles.length) }, worker));
  return {
    workflow_count: handles.length,
    started,
    succeeded,
    failed,
    canceled,
    timed_out: timedOut,
    terminal: succeeded + failed + canceled + timedOut,
    elapsed_ms: Date.now() - startedAt,
    statuses,
    same_turn_counters: sameTurnCounters,
  };
}

function collectSameTurnCounters(value: unknown, counters: Record<string, number>): void {
  if (!value || typeof value !== "object") return;
  for (const [key, nested] of Object.entries(value as Record<string, unknown>)) {
    if (typeof nested === "number" && (key.includes("same_turn") || key.endsWith("_effects"))) {
      counters[key] = (counters[key] ?? 0) + nested;
    } else if (Array.isArray(nested)) {
      for (const item of nested) collectSameTurnCounters(item, counters);
    } else if (nested && typeof nested === "object") {
      collectSameTurnCounters(nested, counters);
    }
  }
}

function workflowHandle<Input, Output, Metadata = Record<string, JsonValue>>(
  client: PrismRuntimeClient,
  defaults: RuntimeDefaults,
  appId: string,
  workflowId: string,
  input: Input,
  options: WorkflowStartOptions,
  shardId: string | undefined,
  workflowKey: string,
  workflowRef: string,
): WorkflowRuntimeHandle<Input, Output, Metadata> {
  let startPromise: Promise<WorkflowStartResponse<Output, Input, Metadata>> | undefined;
  const start = () => {
    if (!startPromise) {
      startPromise = client.startWorkflow<Input, Output, Metadata>(
        appId,
        workflowId,
        input,
        defaults,
        { ...options, shardId, key: workflowKey },
      );
    }
    return startPromise;
  };
  return {
    appId,
    workflowId,
    workflowKey,
    workflowRef,
    shardId,
    start,
    done: async () => {
      await start();
      const read = await client.waitForWorkflow<Output, Input, Metadata>(
        appId,
        workflowId,
        workflowKey,
        defaults,
        {
          projectId: options.projectId,
          shardId,
          timeoutMs: options.waitTimeoutMs,
          pollIntervalMs: options.pollIntervalMs,
          drain: options.drain ?? true,
          drainMaxCandidates: options.drainMaxCandidates,
          drainMaxRecords: options.drainMaxRecords,
        },
      );
      if (!read.found || !read.instance) {
        throw new Error(`workflow ${appId}.${workflowId}/${workflowKey} was not found`);
      }
      if (!workflowSucceeded(read.instance.status)) {
        const suffix = read.instance.error_message ? `: ${read.instance.error_message}` : "";
        throw new Error(`workflow ${appId}.${workflowId}/${workflowKey} finished with status ${read.instance.status}${suffix}`);
      }
      return read.instance.output as Output;
    },
    read: async () => {
      await start();
      return client.readWorkflow<Output, Input, Metadata>(
        appId,
        workflowId,
        workflowKey,
        defaults,
        { projectId: options.projectId, shardId },
      );
    },
    wait: async (waitOptions = {}) => {
      await start();
      return client.waitForWorkflow<Output, Input, Metadata>(
        appId,
        workflowId,
        workflowKey,
        defaults,
        { ...waitOptions, projectId: waitOptions.projectId ?? options.projectId, shardId: waitOptions.shardId ?? shardId },
      );
    },
    cancel: async (reason, cancelOptions = {}) => client.cancelWorkflow<Output, Input, Metadata>(
      workflowKey,
      defaults,
      { ...cancelOptions, projectId: cancelOptions.projectId ?? options.projectId, shardId: cancelOptions.shardId ?? shardId, reason: reason ?? cancelOptions.reason },
    ),
    updateMetadata: async (metadata, updateOptions = {}) => client.updateWorkflowMetadata<Metadata>(
      workflowKey,
      metadata,
      defaults,
      { ...updateOptions, projectId: updateOptions.projectId ?? options.projectId, shardId: updateOptions.shardId ?? shardId },
    ),
    restart: async (restartInput = input, restartOptions = {}) => {
      startPromise = client.startWorkflow<Input, Output, Metadata>(
        appId,
        workflowId,
        restartInput,
        defaults,
        { ...options, ...restartOptions, shardId: restartOptions.shardId ?? shardId, key: workflowKey, mode: "replace_terminal" },
      );
      return startPromise;
    },
    explain: async (inspectOptions = {}) => client.inspectWorkflow(
      defaults,
      {
        ...inspectOptions,
        projectId: inspectOptions.projectId ?? options.projectId,
        shardId: inspectOptions.shardId ?? shardId,
        appFilter: appId,
        workflowFilter: workflowId,
        workflowKeys: [workflowKey],
      },
    ),
  };
}

